import React, { useState } from "react";
import EspacioContacto from "./componentes/espacio-contacto/espacio-contacto";
import IniciarS from "./componentes/iniciar-s/iniciar-s";
import Registrarse from "./componentes/registrarse/registrarse";
import "./contacto.css";

function Contacto() {
    const [showLogin, setShowLogin] = useState(true);

    const toggleForm = () => {
        setShowLogin(prevState => !prevState);
    };

    return (
        <div className="contacto-container">
            <IniciarS 
                opacity={showLogin ? 1 : 1} 
                filter={showLogin ? 0 : 0} 
                toggleForm={toggleForm} 
            />
            <Registrarse 
                opacity={showLogin ? 1 : 1} 
                filter={showLogin ? 0 : 0} 
                toggleForm={toggleForm} 
            />
        </div>
    );
}

export default Contacto;
